    DisjointSet* ds = (DisjointSet*)malloc(sizeof(DisjointSet));
    ds->parent = (int*)malloc((n + 1) * sizeof(int));
    ds->rank = (int*)malloc((n + 1) * sizeof(int));
    for (int i = 1; i <= n; i++) {
        ds->parent[i] = i;
        ds->rank[i] = 0;
    }
    return ds;
}

