    if (node != ds->parent[node]) {
        ds->parent[node] = find(ds, ds->parent[node]);
    }
    return ds->parent[node];
}

void unionSets(DisjointSet* ds, int u, int v) {
    int leader_u = find(ds, u);
    int leader_v = find(ds, v);
    if (leader_u != leader_v) {
        if (ds->rank[leader_u] > ds->rank[leader_v]) {
            int temp = u;
            u = v;
            v = temp;
            temp = leader_u;
            leader_u = leader_v;
            leader_v = temp;
        }
        if (ds->rank[leader_u] == ds->rank[leader_v]) {
            ds->rank[leader_v]++;
        }
        ds->parent[leader_u] = leader_v;
    }
}

